const file = $input.first().json;
const name = file.name || '';
const mime = file.mimeType || '';

// Detect if video or text
const isVideo = mime.startsWith('video/') || /\.(mp4|mov|webm|mkv)$/i.test(name);
const isText = /\.(txt|md|srt)$/i.test(name);

if (!isVideo && !isText) {
  throw new Error('Unsupported file type: ' + name + ' (' + mime + '). Drop .mp4 video or .txt/.md/.srt transcript.');
}

// Detect content type from parent folder
const parents = (file.parents || []).map(p => (p.name || '').toLowerCase());
const folderPath = parents.join('/').toLowerCase();

let contentType = 'technical-walkthrough';
if (folderPath.includes('case-study') || folderPath.includes('casestudy')) contentType = 'case-study';
else if (folderPath.includes('podcast')) contentType = 'podcast';
else if (folderPath.includes('technical') || folderPath.includes('walkthrough') || folderPath.includes('demo')) contentType = 'technical-walkthrough';

// Parse speaker + company from filename: SpeakerName_Company_Title.ext
const baseName = name.replace(/\.[^.]+$/, '');
const parts = baseName.split('_').map(p => p.trim());
let speakerName = '', company = '', title = baseName;

if (parts.length >= 3) {
  speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2');
  company = parts[1].replace(/([a-z])([A-Z])/g, '$1 $2');
  title = parts.slice(2).join(' ');
} else if (parts.length === 2) {
  speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2');
  title = parts[1];
}

return [{
  json: {
    fileId: file.id,
    fileName: name,
    isVideo,
    isText,
    contentType,
    speakerName,
    company,
    title,
    mimeType: mime
  }
}];

const whisper = $input.first().json;
const meta = $('Detect File Type + Content Type').first().json;

// Build timestamped transcript from Whisper segments
let transcript = '';
if (whisper.segments && whisper.segments.length > 0) {
  transcript = whisper.segments.map(seg => {
    const startMin = Math.floor(seg.start / 60);
    const startSec = Math.floor(seg.start % 60);
    const ts = `${String(startMin).padStart(2, '0')}:${String(startSec).padStart(2, '0')}`;
    return `[${ts}] ${seg.text.trim()}`;
  }).join('\n');
} else {
  transcript = whisper.text || '';
}

return [{
  json: {
    body: {
      contentType: meta.contentType,
      transcript,
      videoUrl: '',
      speakerName: meta.speakerName,
      company: meta.company,
      metrics: [],
      title: meta.title
    },
    fileId: meta.fileId,
    fileName: meta.fileName,
    transcriptLength: transcript.length,
    segmentCount: whisper.segments?.length || 0,
    duration: whisper.duration || 0
  }
}];

const item = $input.first();
const meta = $('Detect File Type + Content Type').first().json;

let transcript = '';
if (item.binary?.data) {
  transcript = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
} else if (item.json?.data) {
  transcript = item.json.data;
}

if (!transcript || transcript.trim().length < 20) {
  throw new Error('Transcript too short: ' + (transcript || '').substring(0, 50));
}

return [{
  json: {
    body: {
      contentType: meta.contentType,
      transcript,
      videoUrl: '',
      speakerName: meta.speakerName,
      company: meta.company,
      metrics: [],
      title: meta.title
    },
    fileId: meta.fileId,
    fileName: meta.fileName,
    transcriptLength: transcript.length
  }
}];

const input = $input.first().json;
const body = input.body;
const contentType = body.contentType || 'technical-walkthrough';

const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};

const systemPrompt = `You are a B-roll scene generator for short-form video. Output JSON for CUTAWAY format (full-screen speaker with animated graphics overlaying at key moments).

Output: { "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...} }], "textStrip": { "labels": [{ "from": <frame>, "label": "<text>" }] } }

Flow: ${FLOWS[contentType] || FLOWS['technical-walkthrough']}

Types: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color}]}), workflow-pipeline({header,rows[[{label,sub?,glow?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name}]}), cta-comment({action,keyword})

CUTAWAY RULES:
1. Speaker video plays full-screen. Graphics OVERLAY the speaker.
2. First 5-10 seconds: speaker visible (no overlay). Last 5-10 seconds: speaker visible.
3. Between: animated graphics cover the speaker at key moments.
4. Each scene must match what speaker says at that exact moment.
5. frame=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Min 180 frames.
6. Output ONLY JSON.`;

const context = [body.speakerName ? `Speaker: ${body.speakerName}` : '', body.company ? `Company: ${body.company}` : ''].filter(Boolean).join('
');
const userMessage = `${context ? context + '

' : ''}Transcript:
${body.transcript}`;

return [{ json: { ...input, systemPrompt, userMessage, contentType, title: body.title } }];

const prev = $('Build Claude Prompt').first().json;
const response = $input.first().json;
const content = response.content?.[0]?.text || '';

let config;
try {
  config = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) config = JSON.parse(match[0]);
  else throw new Error('Failed to parse scene JSON');
}

const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);
if (!config.meta || !config.scenes?.length) throw new Error('Invalid config');

return [{ json: {
  config,
  totalFrames,
  totalSeconds: (totalFrames / 30).toFixed(1),
  sceneCount: config.scenes.length,
  sceneTypes: config.scenes.map(s => s.type),
  title: prev.title,
  contentType: prev.contentType,
  sourceFileId: prev.fileId,
  sourceFileName: prev.fileName,
  generatedAt: new Date().toISOString()
} }];
